local function applyRagdoll(p1) --[[ applyRagdoll | Line: 11 ]]
	local Humanoid = p1:FindFirstChildOfClass("Humanoid")
	if not Humanoid then
		return
	end
	Humanoid:ChangeState(Enum.HumanoidStateType.Physics)
	for i, v in ipairs(p1:GetDescendants()) do
		if v:IsA("Motor6D") then
			local Attachment = Instance.new("Attachment")
			local Attachment_2 = Instance.new("Attachment")
			Attachment.Parent = v.Part0
			Attachment_2.Parent = v.Part1
			local BallSocketConstraint = Instance.new("BallSocketConstraint")
			BallSocketConstraint.Attachment0 = Attachment
			BallSocketConstraint.Attachment1 = Attachment_2
			BallSocketConstraint.Parent = v.Part0
			v.Enabled = false
		end
	end
end
local function removeRagdoll(p1) --[[ removeRagdoll | Line: 30 ]]
	local Humanoid = p1:FindFirstChildOfClass("Humanoid")
	if not Humanoid then
		return
	end
	for i, v in ipairs(p1:GetDescendants()) do
		if v:IsA("Motor6D") then
			v.Enabled = true
			continue
		end
		if v:IsA("BallSocketConstraint") then
			v:Destroy()
			continue
		end
		if v:IsA("Attachment") and v.Name == "Attachment" then
			v:Destroy()
		end
	end
	Humanoid:ChangeState(Enum.HumanoidStateType.GettingUp)
end
