	Packets.Ragdoll.OnClientEvent:Connect(function() --[[ Line: 43 | Upvalues: LocalPlayer (ref), applyRagdoll (ref), removeRagdoll (ref) ]]
		local Character = LocalPlayer.Character
		if Character then
			applyRagdoll(Character)
			task.delay(3, function() --[[ Line: 47 | Upvalues: LocalPlayer (ref), removeRagdoll (ref) ]]
				local Character = LocalPlayer.Character
				if not Character then
					return
				end
