			end)
		end
	end)
	local LuckEffect = LocalPlayer:WaitForChild("PlayerGui"):WaitForChild("MainGui"):WaitForChild("HUD"):WaitForChild("PerksInfo"):WaitForChild("LuckEffect")
	local icon67 = LuckEffect:WaitForChild("icon67")
	local X = LuckEffect:WaitForChild("X")
	icon67.Image = "rbxassetid://84724821491115"
	X.Text = "x2"
	LuckEffect.Visible = false
	Packets.SpeedBoost.OnClientEvent:Connect(function(p1) --[[ Line: 65 | Upvalues: LuckEffect (copy) ]]
		LuckEffect.Visible = p1 ~= -1
	end)
end
return t

